<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> call_tool</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> tool_name</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> **</span><span style="color:#EBA0AC;font-style:italic;">params</span><span style="color:#9399B2;">):</span></span>
